USE P21Import;
SET NOCOUNT ON;
DECLARE @ShipmentFileId uniqueidentifier='f5c975af-1d81-5d36-9ff8-244fd38c9fc5';
DECLARE @SupplierID int=40408;

IF OBJECT_ID('tempdb..#cmp') IS NOT NULL DROP TABLE #cmp;
CREATE TABLE #cmp(target_db nvarchar(20), bucket nvarchar(60), line_count int);

;WITH lines AS (
    SELECT shipment_pallet_line_id, PO_No, Item_ID
    FROM P21Import.dbo.coats_mexico_shipment_pallet_line
    WHERE shipment_file_id=@ShipmentFileId
), c AS (
    SELECT l.shipment_pallet_line_id, supplier_matches=COUNT(DISTINCT ivs.inv_mast_uid), po_any=COUNT(DISTINCT pol.po_line_uid), po_open=COUNT(DISTINCT CASE WHEN pol.complete <> 'Y' THEN pol.po_line_uid END), po_complete=COUNT(DISTINCT CASE WHEN pol.complete='Y' AND ISNULL(pol.cancel_flag,'N')<>'Y' THEN pol.po_line_uid END)
    FROM lines l
    LEFT JOIN P21Import.dbo.inventory_supplier ivs ON ivs.supplier_id=@SupplierID AND ivs.supplier_part_no=l.Item_ID
    LEFT JOIN P21Import.dbo.inv_mast ivm ON ivm.inv_mast_uid=ivs.inv_mast_uid AND ISNULL(ivm.delete_flag,'N')<>'Y'
    LEFT JOIN P21Import.dbo.po_line pol ON pol.po_no=l.PO_No AND pol.inv_mast_uid=ivm.inv_mast_uid
    GROUP BY l.shipment_pallet_line_id
)
INSERT #cmp
SELECT 'P21Import', CASE WHEN supplier_matches=0 THEN 'missing_supplier' WHEN po_any=0 THEN 'missing_po_any_status' WHEN po_open=0 AND po_complete>0 THEN 'completed_only' WHEN po_open>0 THEN 'open_match' ELSE 'other' END, COUNT(*)
FROM c GROUP BY CASE WHEN supplier_matches=0 THEN 'missing_supplier' WHEN po_any=0 THEN 'missing_po_any_status' WHEN po_open=0 AND po_complete>0 THEN 'completed_only' WHEN po_open>0 THEN 'open_match' ELSE 'other' END;

;WITH lines AS (
    SELECT shipment_pallet_line_id, PO_No, Item_ID
    FROM P21Import.dbo.coats_mexico_shipment_pallet_line
    WHERE shipment_file_id=@ShipmentFileId
), c AS (
    SELECT l.shipment_pallet_line_id, supplier_matches=COUNT(DISTINCT ivs.inv_mast_uid), po_any=COUNT(DISTINCT pol.po_line_uid), po_open=COUNT(DISTINCT CASE WHEN pol.complete <> 'Y' THEN pol.po_line_uid END), po_complete=COUNT(DISTINCT CASE WHEN pol.complete='Y' AND ISNULL(pol.cancel_flag,'N')<>'Y' THEN pol.po_line_uid END)
    FROM lines l
    LEFT JOIN P21Play.dbo.inventory_supplier ivs ON ivs.supplier_id=@SupplierID AND ivs.supplier_part_no=l.Item_ID
    LEFT JOIN P21Play.dbo.inv_mast ivm ON ivm.inv_mast_uid=ivs.inv_mast_uid AND ISNULL(ivm.delete_flag,'N')<>'Y'
    LEFT JOIN P21Play.dbo.po_line pol ON pol.po_no=l.PO_No AND pol.inv_mast_uid=ivm.inv_mast_uid
    GROUP BY l.shipment_pallet_line_id
)
INSERT #cmp
SELECT 'P21Play', CASE WHEN supplier_matches=0 THEN 'missing_supplier' WHEN po_any=0 THEN 'missing_po_any_status' WHEN po_open=0 AND po_complete>0 THEN 'completed_only' WHEN po_open>0 THEN 'open_match' ELSE 'other' END, COUNT(*)
FROM c GROUP BY CASE WHEN supplier_matches=0 THEN 'missing_supplier' WHEN po_any=0 THEN 'missing_po_any_status' WHEN po_open=0 AND po_complete>0 THEN 'completed_only' WHEN po_open>0 THEN 'open_match' ELSE 'other' END;

SELECT target_db, bucket, line_count=CONVERT(nvarchar(20), line_count) FROM #cmp ORDER BY target_db, bucket;
